function processScores() {
  var functionLevel = 'I exist everywhere in this function';

  if (true) {
    var alsoFunctionLevel = 'var ignores the if-block boundary';
    let blockLevel = 'I am trapped inside this if-block';
    console.log(blockLevel); //  accessible here
  }

  console.log(functionLevel);      // 
  console.log(alsoFunctionLevel);  //  var leaked out of if-block
  // console.log(blockLevel);      //  ReferenceError — let respects block
}

processScores();
// console.log(functionLevel); //  ReferenceError — function scope boundary

6_edge_case.code:
function outer() {
  function inner() {
    var secret = 42; // scoped to 'inner' only
  }
  inner();
  // console.log(secret); //  ReferenceError — 'var' stops at 'inner' function boundary
}
outer();
